import React from "react";


const Pricing = () => {
    return (
        <>
        <div>
        <div className="container">
            <h3>C3Ops Pricing Plans</h3>
            <h4>FinOps-Driven DevOps Platform + Expert Engineers</h4>
            <h6>Choose the plan that matches your organization's cloud spend and optimization needs</h6>
        </div>
        </div>
        </>
    )
}

export default Pricing;
